void preprocessApprovalUrls(Map<String, Set<Integer>> cache_formUrl_rootNodeIds, JSONArray approvalUrls, String action, RagicBundle bundle) {
	for(int i = 0; i < approvalUrls.length(); i++) {
        String approvalUrl = approvalUrls.optString(i, null);
        if(approvalUrl == null) continue;
        String[] secs = approvalUrl.split("/");
        if(secs.length != 4) continue;
        String apname = secs[0];
        String path = "/" + secs[1];
        int sheetIndex = Encoder.parseInt(secs[2], -1);
        if(sheetIndex == -1) continue;
        
        NUIForm form = AppManager.getFormPage(apname, path, sheetIndex);
        if(form == null) continue;
        if("reject".equals(action) && !form.isAllowedApprovalRejection()) {
            throw new RuntimeException(bundle.getString("approvalReport_execute_notAllowReject", new Object[] {form.getRealname()}));
        }
        
        int rootNodeId = Encoder.parseInt(secs[3], -1);
        if(rootNodeId == -1) continue;
        String formUrl = apname + path + "/" + sheetIndex;
        
        Set<Integer> rootNodeIds = cache_formUrl_rootNodeIds.get(formUrl);
        if(rootNodeIds == null) {
            rootNodeIds = new HashSet<>();
            cache_formUrl_rootNodeIds.put(formUrl, rootNodeIds);
        }
        rootNodeIds.add(rootNodeId);
    }
}
