    String loggedInUserPassword = request.getParameter("pwd");
    if(loggedInUserPassword == null || RemoteAccountManager.main_authenticateUser(loggedInUser.getUserId(), loggedInUserPassword, "PWD") == null) {
    	throw new Exception(bundle.getString("massApproval_execution_failed_wrongPassword"));   
    }
