    User approvingUser = null;
    boolean ifDeputy = Encoder.parseBoolean(request.getParameter("ifDeputy"), false);
    if(!ifDeputy) {
    	approvingUser = loggedInUser;
    } else {
        String approvingUserId = request.getParameter("approvingUserId");
        if(approvingUserId == null || approvingUserId.trim().isEmpty()) throw new Exception("Param missing: approvingUserId");
        approvingUser = RemoteAccountManager.main_userInfo(approvingUserId);
        if(approvingUser == null) throw new Exception("User not exist: " + approvingUserId);
    }
