    JSONArray approvalUrls = new JSONArray(request.getParameter("records"));
    this.preprocessApprovalUrls(cache_formUrl_rootNodeIds, approvalUrls, action, bundle);
    ApprovalReportExecutor approvalThread=new ApprovalReportExecutor(
            apname,
            cache_formUrl_rootNodeIds,
            approvingUser, loggedInUser,
            action,
            comment,
            ifDeputy,
            bundle);
    Thread t = new Thread(approvalThread);
